SELECT * FROM orders;
SELECT t.id,t.name,t.created_at FROM orders AS t WHERE t.status = 'active';
SELECT t.id,t.name AS customer_name,t.total_amount AS amount FROM orders AS t;
SELECT DISTINCT t.customer_id,t.status FROM orders AS t;
SELECT o.id,o.total_amount,c.name AS customer_name FROM orders AS o INNER JOIN customers AS c ON c.id = o.customer_id WHERE o.status = 'active';
SELECT c.id,c.name,o.total_amount FROM customers AS c LEFT JOIN orders AS o ON o.customer_id = c.id;
SELECT o.id,c.name AS customer_name,p.name AS product_name,oi.quantity FROM orders AS o INNER JOIN customers AS c ON c.id = o.customer_id INNER JOIN order_items AS oi ON oi.order_id = o.id INNER JOIN products AS p ON p.id = oi.product_id;
SELECT o.id,o.total_amount,c.name FROM orders AS o RIGHT JOIN customers AS c ON c.id = o.customer_id;
SELECT o.id,c.name FROM orders AS o FULL OUTER JOIN customers AS c ON c.id = o.customer_id;
SELECT s.name AS size,c.name AS colour FROM sizes AS s CROSS JOIN colours AS c;
SELECT o.id,c.name FROM orders AS o INNER JOIN customers AS c USING (customer_id);
SELECT t.status,count(*) AS order_count,sum(t.total_amount) AS total FROM orders AS t GROUP BY t.status HAVING count(*) > 10;
SELECT t.id,t.created_at,t.total_amount FROM orders AS t ORDER BY t.created_at DESC,t.id ASC;
SELECT t.id,t.name FROM products AS t ORDER BY t.name ASC OFFSET 40 ROWS FETCH NEXT 20 ROWS ONLY;
SELECT s.status,s.order_count FROM (SELECT t.status,count(*) AS order_count FROM orders AS t GROUP BY t.status) AS s WHERE s.order_count > 5;
SELECT t.id,t.name FROM customers AS t WHERE t.id IN (SELECT o.customer_id FROM orders AS o WHERE o.status = 'active');
SELECT t.id,t.name FROM customers AS t WHERE EXISTS (SELECT 1 FROM orders AS o WHERE o.customer_id = t.id);
WITH active_orders AS (SELECT t.id,t.customer_id,t.total_amount FROM orders AS t WHERE t.status = 'active') SELECT c.name,sum(o.total_amount) AS lifetime_value FROM active_orders AS o INNER JOIN customers AS c ON c.id = o.customer_id GROUP BY c.name ORDER BY lifetime_value DESC;
WITH active_orders AS (SELECT t.id,t.customer_id FROM orders AS t WHERE t.status = 'active'),order_totals AS (SELECT t.customer_id,count(*) AS order_count FROM active_orders AS t GROUP BY t.customer_id) SELECT c.name,ot.order_count FROM order_totals AS ot INNER JOIN customers AS c ON c.id = ot.customer_id;
SELECT t.id,t.customer_id,t.total_amount,row_number() OVER (PARTITION BY t.customer_id ORDER BY t.created_at DESC) AS rn FROM orders AS t;
SELECT t.id,t.total_amount,rank() OVER (ORDER BY t.total_amount DESC) AS amount_rank FROM orders AS t;
SELECT DISTINCT c.id,c.name AS customer_name,sum(o.total_amount) AS lifetime_value,count(o.id) AS order_count,row_number() OVER (ORDER BY sum(o.total_amount) DESC) AS value_rank FROM customers AS c INNER JOIN orders AS o ON o.customer_id = c.id WHERE c.created_at >= '2024-01-01' GROUP BY c.id,c.name HAVING sum(o.total_amount) > 1000 ORDER BY lifetime_value DESC FETCH NEXT 100 ROWS ONLY;
SELECT t.id,t.name FROM orders AS t WHERE t.status = 'active' AND t.region = 'us' AND t.amount > 100;
SELECT t.status,count(*) AS order_count FROM orders AS t GROUP BY t.status HAVING count(*) > 10 AND sum(t.amount) > 1000;
SELECT o.id,o.status FROM orders AS o INNER JOIN customers AS c ON c.id = o.customer_id AND c.active = 1 WHERE o.status = 'active' AND o.total_amount > 0;
SELECT COUNT(*) AS total,SUM(t.amount) AS revenue,AVG(t.amount) AS avg_amount FROM orders AS t;
